jQuery(document).ready(function($){$('.sfwd-courses .hanor-item').click(function(e){e.preventDefault();window.location.href=$(this).find('a').attr('href')});$('#sidebar-toggle').click(function(e){e.preventDefault();$('#floating-sidebar').toggleClass('active');$(this).toggleClass('change')})
$('.toggleaction').click(function(e){e.preventDefault();$(this).parent().parent().toggleClass('isClicked');var self=$(this);$(this).parent().parent().find('.togglerow').slideToggle(250,function(){self.parent().parent().find('.toggleaction .ld-icon').toggleClass('ld-icon-arrow-down');self.parent().parent().find('.toggleaction .ld-icon').toggleClass('ld-icon-arrow-up')});console.log('slidetoggle')});$('a[href="#drtim-modal"]').click(function(e){console.log('click');e.preventDefault();e.stopImmediatePropagation();if(undefined!==$('#download-modal')&&null!=$('#download-modal')){$('#download-modal').fadeIn()}});$('body').click(function(e){if(undefined!==$('#download-modal')&&null!=$('#download-modal')){$('#download-modal').fadeOut()}});$('#download-modal > div').click(function(e){event.stopImmediatePropagation()});$('#download-modal .close-download-modal').click(function(e){e.preventDefault();$('#download-modal').fadeOut()})})